def load_problems():
    if os.path.exists(PROB_FILE):
        try:
            with open(PROB_FILE, 'r', encoding='utf-8') as f:
                saved = json.load(f)
            # If the built-in list has more problems than the saved file,
            # merge: keep saved problems (to preserve any user edits) and
            # add any new built-in problems that aren't already present.
            saved_ids = {p['id'] for p in saved}
            added_new = False
            for p in PROBLEMS:
                if p['id'] not in saved_ids:
                    saved.append(p)
                    added_new = True
            if added_new:
                save_problems(saved)
            return saved
        except:
            pass
    # No file yet — write the full built-in list
    save_problems(PROBLEMS)
    return PROBLEMS

def save_problems(problems):
    with open(PROB_FILE, 'w', encoding='utf-8') as f:
        json.dump(problems, f, indent=2, ensure_ascii=False)

