# ════════════════════════════════════════════════════════════════
#  HTTP SERVER
# ════════════════════════════════════════════════════════════════

class ThreadedHTTPServer(ThreadingMixIn, HTTPServer):
    """Handle each request in a separate thread — eliminates queuing delays."""
    daemon_threads = True

class Handler(BaseHTTPRequestHandler):
    def log_message(self, fmt, *args):
        pass  # Suppress default logging

    def send_json(self, data, code=200):
        body = json.dumps(data, ensure_ascii=False).encode('utf-8')
        self.send_response(code)
        self.send_header('Content-Type', 'application/json; charset=utf-8')
        self.send_header('Content-Length', len(body))
        self.send_header('Access-Control-Allow-Origin', '*')
        self.end_headers()
        self.wfile.write(body)

    def send_html(self, html: str):
        body = html.encode('utf-8')
        self.send_response(200)
        self.send_header('Content-Type', 'text/html; charset=utf-8')
        self.send_header('Content-Length', len(body))
        self.end_headers()
        self.wfile.write(body)

    def read_body(self):
        length = int(self.headers.get('Content-Length', 0))
        return self.rfile.read(length).decode('utf-8')

    def do_OPTIONS(self):
        self.send_response(200)
        self.send_header('Access-Control-Allow-Origin', '*')
        self.send_header('Access-Control-Allow-Methods', 'GET,POST,DELETE')
        self.send_header('Access-Control-Allow-Headers', 'Content-Type')
        self.end_headers()

    def do_GET(self):
        path = urlparse(self.path).path
        if path == '/':
            self.send_html(HTML_PAGE)
        elif path == '/api/problems':
            self.send_json(load_problems())
        elif path.startswith('/api/problems/'):
            pid = int(path.split('/')[-1])
            probs = load_problems()
            p = next((x for x in probs if x['id'] == pid), None)
            if p: self.send_json(p)
            else:  self.send_json({'error':'not found'}, 404)
        elif path == '/api/user-code':
            self.send_json(load_user_code())
        elif path == '/api/stats':
            self.send_json(load_stats())
        elif path == '/api/submissions':
            self.send_json(load_submissions())
        elif path == '/api/playlists':
            self.send_json(load_playlists())
        elif path == '/api/notes':
            self.send_json(load_notes())
        elif path == '/api/tests':
            self.send_json(load_tests())
        elif path == '/api/ping':
            global _last_ping
            _last_ping = time.time()
            self.send_json({'ok': True})
        else:
            self.send_response(404); self.end_headers()

    def do_POST(self):
        path = urlparse(self.path).path
        data = json.loads(self.read_body() or '{}')

        if path == '/api/run':
            ok, out, err = compile_and_run(
                data.get('code',''), data.get('input','')
            )
            self.send_json({'success': ok, 'output': out, 'error': err})

        elif path == '/api/submit':
            code   = data.get('code', '')
            pid    = data.get('id')
            probs  = load_problems()
            prob   = next((p for p in probs if p['id'] == pid), None)
            if not prob:
                self.send_json({'error':'problem not found'}, 404); return

            # ── Compile ONCE, run each test case on the same binary ──
            compile_ok, exe, compile_err, tmpdir = compile_code(code)
            try:
                if not compile_ok:
                    self.send_json({'error': compile_err}); return
                results = []
                passed  = 0
                for tc in prob['testCases']:
                    ok, out, err = _run_exe(exe, tc['input'])
                    actual   = out.strip()
                    expected = tc['expected'].strip()
                    verdict  = ok and (actual == expected)
                    if verdict: passed += 1
                    results.append({
                        'input':    tc['input'],
                        'expected': expected,
                        'actual':   actual,
                        'passed':   verdict,
                        'error':    err
                    })
            finally:
                shutil.rmtree(tmpdir, ignore_errors=True)
            # ─────────────────────────────────────────────────────────

            self.send_json({
                'results': results,
                'passed':  passed,
                'total':   len(results)
            })

        elif path == '/api/problems/add':
            try:
                probs = load_problems()
                new_id = max((p['id'] for p in probs), default=0) + 1
                data['id'] = new_id
                probs.append(data)
                save_problems(probs)
                self.send_json({'id': new_id})
            except Exception as e:
                self.send_json({'error': f'Failed to save problem: {str(e)}'}, 500)

        elif path == '/api/problems/update':
            try:
                probs = load_problems()
                pid = data.get('id')
                for i, p in enumerate(probs):
                    if p['id'] == pid:
                        probs[i] = data
                        break
                save_problems(probs)
                self.send_json({'ok': True})
            except Exception as e:
                self.send_json({'error': f'Failed to update problem: {str(e)}'}, 500)

        elif path == '/api/save-code':
            codes = load_user_code()
            codes[str(data['id'])] = data['code']
            save_user_code(codes)
            self.send_json({'ok': True})
            return

        elif path == '/api/stats/solve':
            stats = load_stats()
            from datetime import date, timedelta
            today = date.today().isoformat()
            # Daily solves
            pid = str(data.get('problemId', ''))
            if today not in stats['dailySolves']:
                stats['dailySolves'][today] = []
            if pid not in [str(x) for x in stats['dailySolves'][today]]:
                stats['dailySolves'][today].append(pid)
                stats['totalSolves'] = stats.get('totalSolves', 0) + 1
            # Streak logic
            last = stats.get('lastSolveDate')
            if last is None:
                stats['currentStreak'] = 1
            elif last == today:
                pass  # already counted today
            else:
                last_d = date.fromisoformat(last)
                diff = (date.today() - last_d).days
                if diff == 1:
                    stats['currentStreak'] = stats.get('currentStreak', 0) + 1
                else:
                    stats['currentStreak'] = 1
            stats['lastSolveDate'] = today
            stats['longestStreak'] = max(stats.get('longestStreak', 0), stats['currentStreak'])
            # Speed solve tracking
            solve_time = data.get('solveTime')
            if solve_time and solve_time < 60:
                stats.setdefault('speedSolves', []).append({
                    'problemId': pid, 'time': solve_time, 'date': today
                })
            save_stats(stats)
            self.send_json({'ok': True, 'stats': stats})

        elif path == '/api/stats/time':
            # Accumulate total platform time (seconds)
            stats = load_stats()
            stats['totalTimeSeconds'] = stats.get('totalTimeSeconds', 0) + data.get('seconds', 0)
            save_stats(stats)
            self.send_json({'ok': True, 'totalTimeSeconds': stats['totalTimeSeconds']})

        elif path == '/api/stats/reset':
            # Preserve totalTimeSeconds — it is NEVER reset
            existing = load_stats()
            preserved_time = existing.get('totalTimeSeconds', 0)
            save_stats({
                "dailySolves": {},
                "currentStreak": 0,
                "longestStreak": 0,
                "lastSolveDate": None,
                "speedSolves": [],
                "totalSolves": 0,
                "totalTimeSeconds": preserved_time,
                "achievements": {}
            })
            self.send_json({'ok': True})

        elif path == '/api/stats/achievements':
            # Save newly unlocked achievements into user_stats.json
            stats = load_stats()
            if 'achievements' not in stats:
                stats['achievements'] = {}
            for ach_id, unlocked_date in data.items():
                if ach_id not in stats['achievements']:
                    stats['achievements'][ach_id] = unlocked_date
            save_stats(stats)
            self.send_json({'ok': True})

        elif path == '/api/submissions/save':
            # Save every submission (pass or fail) with timestamp
            import datetime
            subs = load_submissions()
            record = {
                'ts':          datetime.datetime.now().isoformat(timespec='seconds'),
                'problemId':   data.get('problemId'),
                'problemTitle':data.get('problemTitle', ''),
                'difficulty':  data.get('difficulty', ''),
                'passed':      data.get('passed', 0),
                'total':       data.get('total', 0),
                'verdict':     'Accepted' if data.get('passed') == data.get('total') else 'Wrong Answer',
                'code':        data.get('code', '')
            }
            subs.insert(0, record)   # newest first
            subs = subs[:500]        # keep at most 500 entries
            save_submissions(subs)
            self.send_json({'ok': True})

        elif path == '/api/playlists/create':
            name = (data.get('name') or '').strip()
            if not name:
                self.send_json({'error': 'Name required'}, 400); return
            playlists = load_playlists()
            if name in playlists:
                self.send_json({'error': 'Playlist already exists'}, 409); return
            playlists[name] = []
            save_playlists(playlists)
            self.send_json({'ok': True, 'playlists': playlists})

        elif path == '/api/notes/save':
            import datetime, uuid
            notes = load_notes()
            note = {
                'id':      data.get('id') or str(uuid.uuid4())[:8],
                'tag':     (data.get('tag') or 'General').strip(),
                'title':   (data.get('title') or '').strip(),
                'content': data.get('content', ''),
                'ts':      datetime.datetime.now().isoformat(timespec='seconds')
            }
            # Update existing note if same id
            idx = next((i for i, n in enumerate(notes) if n['id'] == note['id']), None)
            if idx is not None:
                notes[idx] = note
            else:
                notes.insert(0, note)
            save_notes(notes)
            self.send_json({'ok': True, 'note': note})

        elif path == '/api/playlists/add':
            name   = data.get('name')
            pid    = data.get('problemId')
            playlists = load_playlists()
            if name not in playlists:
                self.send_json({'error': 'Playlist not found'}, 404); return
            if pid not in playlists[name]:
                playlists[name].append(pid)
            save_playlists(playlists)
            self.send_json({'ok': True, 'playlists': playlists})

        elif path == '/api/playlists/remove':
            name   = data.get('name')
            pid    = data.get('problemId')
            playlists = load_playlists()
            if name in playlists and pid in playlists[name]:
                playlists[name].remove(pid)
            save_playlists(playlists)
            self.send_json({'ok': True, 'playlists': playlists})

        elif path == '/api/tests/save':
            import datetime
            tests = load_tests()
            record = {
                'id':          data.get('id', str(int(time.time()))),
                'ts':          datetime.datetime.now().isoformat(timespec='seconds'),
                'score':       data.get('score', 0),
                'total':       data.get('total', 0),
                'timeLimitMin':data.get('timeLimitMin', 0),
                'timeUsedSec': data.get('timeUsedSec', 0),
                'questions':   data.get('questions', [])
            }
            tests.insert(0, record)
            tests = tests[:200]
            save_tests(tests)
            self.send_json({'ok': True, 'record': record})

        else:
            self.send_response(404); self.end_headers()

    def do_DELETE(self):
        path = urlparse(self.path).path
        if path.startswith('/api/problems/'):
            pid = int(path.split('/')[-1])
            probs = load_problems()
            probs = [p for p in probs if p['id'] != pid]
            save_problems(probs)
            self.send_json({'ok': True})
        elif path.startswith('/api/notes/'):
            nid = path[len('/api/notes/'):]
            notes = load_notes()
            notes = [n for n in notes if n['id'] != nid]
            save_notes(notes)
            self.send_json({'ok': True})
        elif path.startswith('/api/playlists/'):
            # DELETE /api/playlists/{name}
            import urllib.parse
            name = urllib.parse.unquote(path[len('/api/playlists/'):])
            playlists = load_playlists()
            if name in playlists:
                del playlists[name]
                save_playlists(playlists)
                self.send_json({'ok': True, 'playlists': playlists})
            else:
                self.send_json({'error': 'Not found'}, 404)
        else:
            self.send_response(404); self.end_headers()

