    { label: '✅ Accuracy Streaks',   ids: ['acc_3','acc_5','acc_7','acc_10','acc_15','acc_20','acc_30','acc_50','acc_100','all_accepted','no_wa_day','wa_then_ac','perfect_day','first_try','ten_in_a_row'] },
