    { label: '🟩 Difficulty — Easy',  ids: ['easy_1','easy_2','easy_3','easy_5','easy_10','easy_master','easy_25','easy_30','easy_50','easy_75','easy_100','easy_150','easy_200','easy_300'] },
    { label: '🟨 Difficulty — Med',   ids: ['medium_1','medium_2','medium_3','medium_5','medium_10','medium_master','medium_25','medium_30','medium_50','medium_75','medium_100','medium_150','medium_200','medium_300','medium_500'] },
    { label: '🟥 Difficulty — Hard',  ids: ['hard_1','hard_2','hard_3','hard_5','hard_7','hard_master','hard_10','hard_15','hard_20','hard_25','hard_30','hard_40','hard_50','hard_75','hard_100','hard_200'] },
